        auto qos = rclcpp::QoS(rclcpp::KeepLast(10))
            .reliable()
            .durability_volatile();

        subscription_ = this->create_subscription<simple_talker_listener::msg::PersonInfo>(
            "person_info",
            qos,
            std::bind(&ListenerNode::person_callback, this, std::placeholders::_1));

