        auto group = create_callback_group(CallbackGroupType::Reentrant);

        service_ = create_service<Trigger>(
            "my_service",
            std::bind(&ServiceNode::handle, this, _1, _2),
            rmw_qos_profile_services_default,
            group  // Reentrant!
        );
